export {
  ResizableItem as Item,
  ResizablePropsContext as PropsContext,
  ResizableRoot as Root,
  ResizableTrigger as Trigger,
  useResizablePropsContext as usePropsContext,
} from "./resizable"
export type {
  ResizableItemProps as ItemProps,
  ResizableRootProps as RootProps,
  ResizableTriggerProps as TriggerProps,
} from "./resizable"
export {
  ResizableContext as Context,
  useResizableContext as useContext,
  useResizableLayout as useLayout,
} from "./use-resizable"
export type {
  ResizableItemControl as ItemControl,
  ResizableRootControl as RootControl,
  ResizableStorage as Storage,
} from "./use-resizable"

import { defineComponentSlotStyle } from "@yamada-ui/react"

export const resizableStyle = defineComponentSlotStyle({
  base: {
    icon: {
      alignItems: "center",
      display: "flex",
      justifyContent: "center",
      left: "50%",
      position: "absolute",
      top: "50%",
      translateX: "-50%",
      translateY: "-50%",
    },
    item: {
      boxSize: "full",
    },
    root: {
      boxSize: "full",
    },
    trigger: {
      position: "relative",
      transitionDuration: "moderate",
      transitionProperty: "common",
      _after: {
        transitionDuration: "moderate",
        transitionProperty: "common",
      },
    },
  },

  variants: {
    border: {
      icon: {
        bg: "colorScheme.muted",
        color: "colorScheme.fg",
        py: "1",
        rounded: "l1",
      },
      trigger: {
        bg: "colorScheme.muted",
        focusVisibleRing: "none",
        _after: {
          position: "absolute",
        },
        _hover: {
          bg: "colorScheme.emphasized",
        },
        _focusVisible: {
          bg: "colorScheme.emphasized",
        },
      },
    },
    plain: {
      trigger: {
        focusVisibleRing: "none",
        _after: {
          position: "absolute",
        },
      },
    },
    spacer: {
      icon: {
        color: "colorScheme.fg",
        transitionDuration: "moderate",
        transitionProperty: "common",
      },
      trigger: {
        focusVisibleRing: "none",
        p: "1",
        _after: {
          bg: "transparent",
          display: "block",
          rounded: "full",
        },
        _hover: {
          _after: {
            bg: "colorScheme.bg",
          },
          _icon: {
            color: "transparent",
          },
        },
        _focusVisible: {
          _after: {
            bg: "colorScheme.bg",
          },
          _icon: {
            color: "transparent",
          },
        },
      },
    },
  },

  props: {
    /**
     * The orientation of the resizable.
     *
     * @default 'horizontal'
     */
    orientation: {
      horizontal: {
        icon: {
          transform: "translate(-50%, -50%) rotate(0deg)",
        },
      },
      vertical: {
        icon: {
          transform: "translate(-50%, -50%) rotate(90deg)",
        },
      },
    },
  },

  compounds: [
    {
      css: {
        trigger: {
          h: "px",
          _after: {
            h: "2",
            left: "0",
            right: "0",
            transform: "translateY(-50%)",
          },
        },
      },
      variant: "border",
      orientation: "vertical",
    },
    {
      css: {
        trigger: {
          w: "px",
          _after: {
            bottom: "0",
            top: "0",
            transform: "translateX(-50%)",
            w: "2",
          },
        },
      },
      variant: "border",
      orientation: "horizontal",
    },
    {
      css: {
        trigger: {
          _after: { h: "2", w: "full" },
        },
      },
      variant: "spacer",
      orientation: "vertical",
    },
    {
      css: {
        trigger: {
          _after: { h: "full", w: "2" },
        },
      },
      variant: "spacer",
      orientation: "horizontal",
    },
    {
      css: {
        trigger: {
          _after: {
            h: "2",
            left: "0",
            right: "0",
            transform: "translateY(-50%)",
          },
        },
      },
      variant: "plain",
      orientation: "vertical",
    },
    {
      css: {
        trigger: {
          _after: {
            bottom: "0",
            top: "0",
            transform: "translateX(-50%)",
            w: "2",
          },
        },
      },
      variant: "plain",
      orientation: "horizontal",
    },
  ],

  defaultProps: {
    variant: "border",
    orientation: "horizontal",
  },
})

export type ResizableStyle = typeof resizableStyle

"use client"

import type { ReactElement } from "react"
import type {
  HTMLStyledProps,
  HTMLStyledPropsWithoutAs,
  ThemeProps,
} from "@yamada-ui/react"
import type { ResizableStyle } from "./resizable.style"
import type {
  UseResizableItemProps,
  UseResizableProps,
  UseResizableTriggerProps,
} from "./use-resizable"
import { useMemo } from "react"
import { Group, Panel, Separator } from "react-resizable-panels"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { resizableStyle } from "./resizable.style"
import {
  ResizableContext,
  useResizable,
  useResizableItem,
  useResizableTrigger,
} from "./use-resizable"

/**
 * `Resizable` is accessible resizable panel groups and layouts with keyboard support.
 *
 * @see https://yamada-ui.com/docs/components/resizable
 */
export interface ResizableRootProps
  extends
    HTMLStyledProps,
    ThemeProps<ResizableStyle>,
    Omit<UseResizableProps, "orientation"> {}

const {
  PropsContext: ResizablePropsContext,
  usePropsContext: useResizablePropsContext,
  withContext,
  withProvider,
} = createSlotComponent<ResizableRootProps, ResizableStyle>(
  "resizable",
  resizableStyle,
)

export { ResizablePropsContext, useResizablePropsContext }

export const ResizableRoot = withProvider<
  "div",
  ResizableRootProps,
  "orientation"
>(
  ({ children, orientation: orientationProp, ...rest }) => {
    const computedOrientation = useValue(orientationProp)
    const { disabled, groupRef, orientation, getRootProps } = useResizable({
      orientation: computedOrientation,
      ...rest,
    })

    const context = useMemo(
      () => ({ disabled, groupRef, orientation }),
      [disabled, orientation, groupRef],
    )

    return (
      <ResizableContext value={context}>
        <styled.div as={Group} {...getRootProps()}>
          {children}
        </styled.div>
      </ResizableContext>
    )
  },
  "root",
  { transferProps: ["orientation"] },
)()

export interface ResizableItemProps
  extends HTMLStyledPropsWithoutAs, UseResizableItemProps {}

export const ResizableItem = withContext<"div", ResizableItemProps>((props) => {
  const { getItemProps } = useResizableItem(props)

  return <styled.div as={Panel} {...getItemProps()} />
}, "item")()

export interface ResizableTriggerProps
  extends HTMLStyledPropsWithoutAs, UseResizableTriggerProps {
  /**
   * The resizable trigger icon to use.
   */
  icon?: ReactElement
  /**
   * Props for resizable trigger icon component.
   */
  iconProps?: HTMLStyledProps
}

export const ResizableTrigger = withContext<"div", ResizableTriggerProps>(
  ({ children, icon, iconProps, ...rest }) => {
    const { getIconProps, getTriggerProps } = useResizableTrigger(rest)

    return (
      <styled.div as={Separator} {...getTriggerProps()}>
        {icon ? (
          <ResizableIcon {...getIconProps(iconProps)}>{icon}</ResizableIcon>
        ) : null}

        {children}
      </styled.div>
    )
  },
  "trigger",
)()

interface ResizableIconProps extends HTMLStyledProps {}

const ResizableIcon = withContext<"div", ResizableIconProps>("div", "icon")()

"use client"

import type { MouseEvent, RefObject } from "react"
import type {
  GroupImperativeHandle,
  GroupProps,
  LayoutStorage,
  PanelImperativeHandle,
  PanelProps,
  SeparatorProps,
} from "react-resizable-panels"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import { useCallback } from "react"
import {
  useGroupRef,
  usePanelRef,
  useDefaultLayout as useResizableLayout,
} from "react-resizable-panels"
import {
  ariaAttr,
  createContext,
  dataAttr,
  fnAll,
  handlerAll,
  mergeRefs,
} from "@yamada-ui/react"

interface ResizableContext extends Omit<UseResizableReturn, "getRootProps"> {}

const [ResizableContext, useResizableContext] = createContext<ResizableContext>(
  {
    name: "ResizableContext",
  },
)

export { ResizableContext, useResizableContext, useResizableLayout }

export interface ResizableStorage extends LayoutStorage {}
export interface ResizableRootControl extends GroupImperativeHandle {}
export interface ResizableItemControl extends PanelImperativeHandle {}

export interface UseResizableProps
  extends
    HTMLProps,
    Omit<GroupProps, "color" | "content" | "elementRef" | "groupRef"> {
  /**
   * Ref of the resizable item callback.
   */
  controlRef?: RefObject<null | ResizableRootControl>
}

export const useResizable = ({
  controlRef,
  disabled,
  orientation = "horizontal",
  ...rest
}: UseResizableProps = {}) => {
  const groupRef = useGroupRef()

  const getRootProps: PropGetter<GroupProps> = useCallback(
    (props = {}) => ({
      disabled,
      orientation,
      ...rest,
      ...props,
      style: {
        height: undefined,
        width: undefined,
        ...rest.style,
        ...props.style,
      },
      elementRef: mergeRefs(props.elementRef, rest.ref),
      groupRef: mergeRefs(props.groupRef, groupRef, controlRef),
      onLayoutChange: fnAll(props.onLayoutChange, rest.onLayoutChange),
      onLayoutChanged: fnAll(props.onLayoutChanged, rest.onLayoutChanged),
    }),
    [disabled, orientation, groupRef, controlRef, rest],
  )

  return {
    disabled,
    groupRef,
    orientation,
    getRootProps,
  }
}

export type UseResizableReturn = ReturnType<typeof useResizable>

export interface UseResizableItemProps
  extends
    HTMLProps,
    Omit<PanelProps, "color" | "content" | "elementRef" | "panelRef"> {
  /**
   * Ref of the resizable item callback.
   */
  controlRef?: RefObject<null | ResizableItemControl>
}

export const useResizableItem = ({
  controlRef,
  ...rest
}: UseResizableItemProps) => {
  const panelRef = usePanelRef()

  const getItemProps: PropGetter<PanelProps> = useCallback(
    (props = {}) => ({
      ...rest,
      ...props,
      elementRef: mergeRefs(props.elementRef, rest.ref),
      panelRef: mergeRefs(props.panelRef, panelRef, controlRef),
      onResize: fnAll(props.onResize, rest.onResize),
    }),
    [panelRef, controlRef, rest],
  )

  return {
    panelRef,
    getItemProps,
  }
}

export type UseResizableItemReturn = ReturnType<typeof useResizableItem>

export interface UseResizableTriggerProps
  extends HTMLProps, Omit<SeparatorProps, "color" | "content" | "elementRef"> {}

export const useResizableTrigger = ({
  disabled,
  ...rest
}: UseResizableTriggerProps) => {
  const {
    disabled: groupDisabled,
    groupRef,
    orientation,
  } = useResizableContext()
  const trulyDisabled = disabled || groupDisabled

  const onDoubleClick = useCallback(
    (ev: MouseEvent<HTMLDivElement>) => {
      ev.preventDefault()

      const layout = groupRef.current?.getLayout()

      if (!layout) return

      const count = Object.keys(layout).length
      const size = 100 / count
      const nextLayout = Object.fromEntries(
        Object.keys(layout).map((key) => [key, size]),
      )

      groupRef.current?.setLayout(nextLayout)
    },
    [groupRef],
  )

  const getTriggerProps: PropGetter<SeparatorProps> = useCallback(
    (props = {}) => ({
      "aria-disabled": ariaAttr(trulyDisabled),
      "aria-orientation": orientation,
      "data-disabled": dataAttr(trulyDisabled),
      disabled: trulyDisabled,
      tabIndex: trulyDisabled ? -1 : 0,
      ...rest,
      ...props,
      elementRef: mergeRefs(props.elementRef, rest.ref),
      onDoubleClick: handlerAll(
        props.onDoubleClick,
        rest.onDoubleClick,
        onDoubleClick,
      ),
    }),
    [orientation, trulyDisabled, rest, onDoubleClick],
  )

  const getIconProps: PropGetter = useCallback(
    (props = {}) => ({
      "data-icon": "",
      ...props,
    }),
    [],
  )

  return {
    getIconProps,
    getTriggerProps,
  }
}

export type UseResizableTriggerReturn = ReturnType<typeof useResizableTrigger>
